let name = null;

// This will cause a TypeError because 'null' is not an object and has no properties
console.log(name.length);

// Fix: Make sure the variable is a string before accessing 'length'
name = "Alice";
console.log(name.length);

function greet(name: string) {
  return `Hello, ${name}!`;
}

console.log(greet('World'));

function double(x: number) {
  return x * 2;
}

const result = double("hello");  // Error: Argument of type 'string' is not assignable to parameter of type 'number'.

SELECT * FROM employees WHERE department_id = NULL;

-- This query will not work as expected because NULL cannot be compared using '=' operator.
-- Correct way to check for NULL is using IS NULL:
SELECT * FROM employees WHERE department_id IS NULL;
